-- ================================================================
-- SEED: Ofertas Hipotecarias — Ofertas, Reglas, Condiciones y Parametros
-- Fuente: doc/offers-settings.md
-- Fecha base de vigencia: 2026-01-01
--
-- Convenciones:
--   · LTV almacenado como ratio decimal (0.80 = 80 %)
--   · Plazo en ANOS (5, 30, 31, 40)
--   · INGRESO_T1_NM = T1.Ingresos * T1.NumPagas / 14
--   · EDAD_MAX_NM = max(edadT1, edadT2); edadT2=0 si NUM_TITULARES_NM=1
--   · FIELD:<campo> referencia otro campo del contexto de entrada
--   · Nomenclatura MRO: _NM (numero), _FL (booleano), _CD (codigo)
--
-- Patron de inversion (De Morgan):
--   Las reglas detectan RECHAZO, no elegibilidad.
--   Las condiciones positivas del spec se niegan para encodar el rechazo.
--   INIT_RECHAZADA_FL / PRE_RECHAZADA_FL acumulan el estado de rechazo;
--   la regla de decision comprueba IS_FALSE y escribe INIT/PRE_ELEGIBLE_FL.
--
-- Ejecucion: dos batches separados por GO.
--   Batch 1 — define procedimiento temporal #ins_joven_rules
--   Batch 2 — limpia, inserta ofertas/params y llama al procedimiento
-- ================================================================

-- ================================================================
-- BATCH 1: Procedimiento reutilizable para las 5 ofertas distintas de FIDELIZACION
--   Parametros OUTPUT: @ruleId, @condId, @actnId
--   Permite que los contadores sean continuos entre llamadas sucesivas.
-- ================================================================
CREATE OR ALTER PROCEDURE #ins_joven_rules
  @rs        INT,
  @offerCode NVARCHAR(50),
  @ruleId    INT OUTPUT,
  @condId    INT OUTPUT,
  @actnId    INT OUTPUT
AS
BEGIN
  SET NOCOUNT ON;
  DECLARE @VF   DATE        = '2026-01-01';
  DECLARE @code NVARCHAR(50) = @offerCode COLLATE DATABASE_DEFAULT;
  DECLARE @r    INT;

  -- ──────────────────────────────────────────────────────────────
  -- FASE INIT — Reglas de rechazo
  -- ──────────────────────────────────────────────────────────────

  -- R1. neg. Antiguedad / Domiciliacion
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'INIT Rechazo: neg. Antiguedad/Domiciliacion',1000,0,@VF,NULL,0);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',                 'EQ',      'STRING','INIT',                 NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','ANTIGUEDAD_T1_NM',      'LE',      'NUMBER','PARAM:MIN_ANTIGUEDAD', NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','DOMICILIA_NOMINA_T1_FL','IS_FALSE','BOOL',  '',                    NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'1','stage',                 'EQ',      'STRING','INIT',                 NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'1','ANTIGUEDAD_T2_NM',      'LE',      'NUMBER','PARAM:MIN_ANTIGUEDAD', NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'1','DOMICILIA_NOMINA_T2_FL','IS_FALSE','BOOL',  '',                    NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET',   'INIT_RECHAZADA_FL','true',                 'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'APPEND','MOTIVOS',           '{"code":"ANTIGUEDAD"}','JSON');

  -- R2. TIPO_ALTA_CD NOT IN TIPO_ALTA_ADMITIDAS
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'INIT Rechazo: Tipo de alta no admitido',970,0,@VF,NULL,1);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',       'EQ',    'STRING','INIT',                     NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','TIPO_ALTA_CD','NOT_IN','STRING','PARAM:TIPO_ALTA_ADMITIDAS',NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET',   'INIT_RECHAZADA_FL','true',                'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'APPEND','MOTIVOS',           '{"code":"TIPO_ALTA"}','JSON');

  -- R3. FINALIDAD_CD <> 15
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'INIT Rechazo: Finalidad diferente de 15 (no primera vivienda)',960,0,@VF,NULL,1);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',       'EQ','STRING','INIT',NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','FINALIDAD_CD','NE','NUMBER','15',  NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET',   'INIT_RECHAZADA_FL','true',                 'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'APPEND','MOTIVOS',           '{"code":"FINALIDAD"}', 'JSON');

  -- R4. PRIMERA_VIVIENDA_HABITUAL_FL <> 0
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'INIT Rechazo: Tiene otras propiedades',950,0,@VF,NULL,0);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',               'EQ','STRING','INIT',NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','PRIMERA_VIVIENDA_HABITUAL_FL','NE','NUMBER','0',   NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET',   'INIT_RECHAZADA_FL','true',                        'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'APPEND','MOTIVOS',           '{"code":"OTRAS_PROPIEDADES"}','JSON');

  -- R5. EDAD_MAX_NM >= MAX_EDAD
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'INIT Rechazo: EDAD_MAX_NM >= MAX_EDAD',940,0,@VF,NULL,0);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',      'EQ','STRING','INIT',           NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','EDAD_MAX_NM','GE','NUMBER','PARAM:MAX_EDAD',NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET',   'INIT_RECHAZADA_FL','true',           'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'APPEND','MOTIVOS',           '{"code":"EDAD"}','JSON');

  -- R6. IMPORTE_VIVIENDA_NM < IMPORTE_VENTA_CA_NM
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'INIT Rechazo: IMPORTE_VIVIENDA_NM < IMPORTE_VENTA_CA_NM (minimo CCAA)',930,0,@VF,NULL,0);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',              'EQ','STRING','INIT',                      NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','IMPORTE_VIVIENDA_NM','LT','NUMBER','FIELD:IMPORTE_VENTA_CA_NM',NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET',   'INIT_RECHAZADA_FL','true',                     'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'APPEND','MOTIVOS',           '{"code":"IMPORTE_VIVIENDA"}','JSON');

  -- R7. INIT Decision — INIT_ELEGIBLE_FL + limites
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'INIT Decision: INIT_ELEGIBLE_FL + limites',10,0,@VF,NULL,1);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',            'EQ',      'STRING','INIT',NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','INIT_RECHAZADA_FL','IS_FALSE','BOOL',  '',    NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','INIT_ELEGIBLE_FL','true',                   'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','MIN_HIPOTECA_NM', 'PARAM:MIN_HIPOTECA',     'NUMBER');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','MAX_HIPOTECA_NM', 'PARAM:MAX_HIPOTECA',     'NUMBER');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','MIN_PLAZO_NM',    'PARAM:MIN_PLAZO',        'NUMBER');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','MAX_PLAZO_NM',    'PARAM:MAX_PLAZO',        'NUMBER');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','MIN_LTV_EXCL_NM', 'PARAM:MIN_LTV_EXCLUSIVE','NUMBER');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','MAX_LTV_NM',      'PARAM:MAX_LTV',          'NUMBER');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','EDAD_PLAZO_NM',   'PARAM:EDAD_PLAZO',       'NUMBER');
  -- SOLICITAR_DATOS_INTERVINIENTES: la UI debe pedir datos de intervinientes
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','SOLICITAR_DATOS_INTERVINIENTES','true','BOOL');

  -- ──────────────────────────────────────────────────────────────
  -- FASE PRE — Reglas de rechazo
  -- ──────────────────────────────────────────────────────────────

  -- R8. 1 titular: INGRESO_T1_NM < MIN_INGRESOS_1T
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'PRE Rechazo: 1T INGRESO_T1_NM < MIN_INGRESOS_1T',900,0,@VF,NULL,0);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',           'EQ','STRING','PRE',                  NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','NUM_TITULARES_NM','EQ','NUMBER','1',                    NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','INGRESO_T1_NM',  'LT','NUMBER','PARAM:MIN_INGRESOS_1T',NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET',   'PRE_RECHAZADA_FL','true',              'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'APPEND','MOTIVOS',          '{"code":"INGRESOS"}','JSON');

  -- R9. 2 titulares: INGRESO_TOTAL_NM <= MIN_INGRESOS_2T
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'PRE Rechazo: 2T INGRESO_TOTAL_NM <= MIN_INGRESOS_2T',890,0,@VF,NULL,0);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',           'EQ','STRING','PRE',                  NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','NUM_TITULARES_NM','EQ','NUMBER','2',                    NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','INGRESO_TOTAL_NM','LE','NUMBER','PARAM:MIN_INGRESOS_2T',NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET',   'PRE_RECHAZADA_FL','true',              'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'APPEND','MOTIVOS',          '{"code":"INGRESOS"}','JSON');

  -- R10. PRE Decision — PRE_ELEGIBLE_FL + limites
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs,N'PRE Decision: PRE_ELEGIBLE_FL + limites',10,0,@VF,NULL,1);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',           'EQ',      'STRING','PRE',NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','PRE_RECHAZADA_FL','IS_FALSE','BOOL',  '',   NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','PRE_ELEGIBLE_FL',   'true',                   'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','OFERTA_GANADORA_CD',@code,                    'STRING');
