  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','RECHAZADA_FL','IS_TRUE','BOOL',  '',    NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','ELEGIBLE_FL',       'false',   'BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','OFERTA_GANADORA_CD','FIDELIZACION','STRING');

  -- FIDELIZACION R5. FINAL Decision: ELEGIBLE
  SET @ruleId += 1; SET @r = @ruleId;
  INSERT INTO dbo.MRO_MOTORREGLA (MOTORREGLA_ID,MOTOROFERTA_ID,MOTORREGLA_DS,PRIORIDAD_NM,BORRADO_FL,VIGENCIA_DESDE_DT,VIGENCIA_HASTA_DT,PARAR_PROCESO_FL)
  VALUES (@r,@rs_clientes,N'FINAL Decision: ELEGIBLE',1,0,@VF,NULL,1);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','stage',       'EQ',      'STRING','FINAL',NULL);
  SET @condId += 1; INSERT INTO dbo.MRO_MOTORCONDICION (MOTORCONDICION_ID,MOTORREGLA_ID,GRUPO_CONDICION_CD,CAMPO_CD,OPERADOR_CD,TIPO_VALOR_CD,VALOR1_DS,VALOR2_DS) VALUES (@condId,@r,'0','RECHAZADA_FL','IS_FALSE','BOOL',  '',    NULL);
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','ELEGIBLE_FL',       'true',    'BOOL');
  -- SOLICITAR_DATOS_INTERVINIENTES: la UI debe pedir datos de intervinientes
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','SOLICITAR_DATOS_INTERVINIENTES','false','BOOL');
  SET @actnId += 1; INSERT INTO dbo.MRO_MOTORACCION (MOTORACCION_ID,MOTORREGLA_ID,TIPO_ACCION_CD,CAMPO_CD,VALOR_DS,TIPO_VALOR_CD) VALUES (@actnId,@r,'SET','OFERTA_GANADORA_CD','FIDELIZACION','STRING');

  -- ──────────────────────────────────────────────────────────────
  -- 4. REGLAS
  --    Los contadores se pasan como OUTPUT para mantener continuidad.
  --    Al entrar: @ruleId=5, @condId=13, @actnId=9
  -- ──────────────────────────────────────────────────────────────
  EXEC #ins_joven_rules @rs_alto_ltv,        'ALTO_RIESGO',                 @ruleId OUTPUT, @condId OUTPUT, @actnId OUTPUT;
  EXEC #ins_joven_rules @rs_mejor_precio,    'PROMOCION',             @ruleId OUTPUT, @condId OUTPUT, @actnId OUTPUT;
  EXEC #ins_joven_rules @rs_alto_plazo,      'LARGO_PLAZO',               @ruleId OUTPUT, @condId OUTPUT, @actnId OUTPUT;
  EXEC #ins_joven_rules @rs_combinada,       'ULTRA_ALTO_RIESGO',                @ruleId OUTPUT, @condId OUTPUT, @actnId OUTPUT;
  EXEC #ins_joven_rules @rs_mejor_precio_av, 'PROMOCION_HC',  @ruleId OUTPUT, @condId OUTPUT, @actnId OUTPUT;

  COMMIT TRANSACTION;
  PRINT 'OK: transaccion completada correctamente.';

END TRY
BEGIN CATCH
  IF @@TRANCOUNT > 0
    ROLLBACK TRANSACTION;
  PRINT 'ERROR en linea ' + CAST(ERROR_LINE() AS NVARCHAR) + ': ' + ERROR_MESSAGE();
  THROW;
END CATCH

-- ──────────────────────────────────────────────────────────────
-- 5. VERIFICACION RAPIDA
--    Valores esperados:
--      ULTRA_ALTO_RIESGO             
--      ALTO_RIESGO                
--      LARGO_PLAZO              
--      PROMOCION_HC 
--      PROMOCION            
--      FIDELIZACION                      
-- ──────────────────────────────────────────────────────────────
SELECT
  h.OFERTA_CD       AS oferta,
  rs.OFERTA_RANK_NM AS rank,
  (SELECT COUNT(*) FROM dbo.MRO_MOTORREGLA r
   WHERE r.MOTOROFERTA_ID = rs.MOTOROFERTA_ID)                                     AS num_reglas,
  (SELECT COUNT(*) FROM dbo.MRO_MOTORCONDICION c
   JOIN dbo.MRO_MOTORREGLA r ON r.MOTORREGLA_ID = c.MOTORREGLA_ID
   WHERE r.MOTOROFERTA_ID = rs.MOTOROFERTA_ID)                                     AS num_condiciones,
  (SELECT COUNT(*) FROM dbo.MRO_MOTORACCION a
   JOIN dbo.MRO_MOTORREGLA r ON r.MOTORREGLA_ID = a.MOTORREGLA_ID
   WHERE r.MOTOROFERTA_ID = rs.MOTOROFERTA_ID)                                     AS num_acciones,
  (SELECT COUNT(*) FROM dbo.MRO_MOTORPARAM p
   WHERE p.MOTOROFERTA_ID = rs.MOTOROFERTA_ID)                                     AS num_params
FROM dbo.MRO_MOTOROFERTA rs
JOIN HIPO_OFERTA h ON h.OFERTA_ID = rs.OFERTA_ID
ORDER BY rs.OFERTA_RANK_NM DESC;
